function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function getMessageText(message) {
  if (!message) return null;
  if (message.text?.body) return message.text.body;
  if (message.button?.text) return message.button.text;
  if (message.interactive?.button_reply?.title) return message.interactive.button_reply.title;
  if (message.interactive?.list_reply?.title) return message.interactive.list_reply.title;
  if (message.image?.caption) return message.image.caption;
  return null;
}

function getSelectionId(message) {
  if (message?.interactive?.button_reply?.id) return message.interactive.button_reply.id;
  if (message?.interactive?.list_reply?.id) return message.interactive.list_reply.id;
  return null;
}

function normalizeText(text) {
  return (text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function normalizePhoneNumber(value) {
  return String(value || "").replace(/\D/g, "");
}

function isAdminMessage(from) {
  return adminNumbers.has(normalizePhoneNumber(from));
}

function detectImageExtension(mimeType) {
  switch (mimeType) {
    case "image/jpeg":
      return ".jpeg";
    case "image/png":
      return ".png";
    case "image/webp":
      return ".webp";
    default:
      return ".jpg";
  }
}

