function wantsMainMenu(text, selectionId) {
  if (selectionId === "action_more_types") return true;
  const normalized = normalizeText(text);
  return ["oi", "ola", "menu", "prancha", "pranchas", "aloha", "quero ver"].some((term) =>
    normalized.includes(normalizeText(term))
  );
}

function detectBoardTypeFromText(text) {
  const normalized = normalizeText(text);
  if (["1", "longboard"].includes(normalized)) return "longboard";
  if (["2", "pranchinha", "shortboard"].includes(normalized)) return "pranchinha";
  if (["3", "fish"].includes(normalized)) return "fish";
  if (["4", "fun", "funboard"].includes(normalized)) return "fun";
  return null;
}

