function slugifyAdminValue(value) {
  return normalizeText(value)
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-{2,}/g, "-");
}

function createBoardId(type, title) {
  const base = `${type}-${slugifyAdminValue(title) || "prancha"}`;
  let candidate = base;
  let counter = 2;

  while (getBoardById(candidate)) {
    candidate = `${base}-${counter}`;
    counter += 1;
  }

  return candidate;
}

